class Solution:
    def countVowelPermutation(self, n):
        MOD = 10**9 + 7
        # follow[x] = vowels that may come AFTER x (a=0,e=1,i=2,o=3,u=4)
        follow = {0: [1], 1: [0, 2], 2: [0, 1, 3, 4], 3: [2, 4], 4: [0]}
        # transition matrix M[next][prev] using matrix exponentiation as an
        # independent counting method
        M = [[0] * 5 for _ in range(5)]
        for prev, nxts in follow.items():
            for nx in nxts:
                M[nx][prev] += 1
        def matmul(A, B):
            r = [[0] * 5 for _ in range(5)]
            for i in range(5):
                for k in range(5):
                    if A[i][k]:
                        aik = A[i][k]
                        for j in range(5):
                            r[i][j] = (r[i][j] + aik * B[k][j]) % MOD
            return r
        def matpow(A, p):
            res = [[1 if i == j else 0 for j in range(5)] for i in range(5)]
            while p:
                if p & 1:
                    res = matmul(res, A)
                A = matmul(A, A)
                p >>= 1
            return res
        P = matpow(M, n - 1)
        total = 0
        for i in range(5):
            for j in range(5):
                total = (total + P[i][j]) % MOD
        return total % MOD

