var countVowelPermutation = function(n) {
    const MOD = 1000000007n;
    let a = 1n, e = 1n, i = 1n, o = 1n, u = 1n;
    for (let s = 1; s < n; s++) {
        const na = (e + i + u) % MOD;
        const ne = (a + i) % MOD;
        const ni = (e + o) % MOD;
        const no = i % MOD;
        const nu = (i + o) % MOD;
        a = na; e = ne; i = ni; o = no; u = nu;
    }
    return Number((a + e + i + o + u) % MOD);
};
